class ChatRoom {
  constructor(name) {
    this.name = name;
    this.clients = new Map(); // username -> ws
  }

  join(username, ws) {
    this.clients.set(username, ws);
    this.broadcast({ type: 'join', user: username, room: this.name });
  }

  leave(username) {
    this.clients.delete(username);
    this.broadcast({ type: 'leave', user: username, room: this.name });
  }

  broadcast(message, excludeUser = null) {
    const data = JSON.stringify(message);
    for (const [user, ws] of this.clients) {
      if (user !== excludeUser && ws.readyState === 1) {
        ws.send(data);
      }
    }
  }

  getMembers() {
    return [...this.clients.keys()];
  }
}

module.exports = { ChatRoom };

const WebSocket = require('ws');
const { ChatRoom } = require('./ChatRoom');

const wss = new WebSocket.Server({ port: 8888 });
const rooms = new Map();
const userSockets = new Map(); // username -> { ws, currentRoom }

function getOrCreateRoom(name) {
  if (!rooms.has(name)) rooms.set(name, new ChatRoom(name));
  return rooms.get(name);
}

wss.on('connection', (ws) => {
  let username = null;

  ws.on('message', (raw) => {
    let msg;
    try { msg = JSON.parse(raw); } catch { return; }

    switch (msg.type) {
      case 'auth': {
        username = msg.username;
        userSockets.set(username, { ws, currentRoom: null });
        ws.send(JSON.stringify({ type: 'auth_ok', username }));
        break;
      }
      case 'join': {
        if (!username) return;
        const room = getOrCreateRoom(msg.room);
        const state = userSockets.get(username);
        if (state.currentRoom) rooms.get(state.currentRoom)?.leave(username);
        state.currentRoom = msg.room;
        room.join(username, ws);
        ws.send(JSON.stringify({ type: 'room_joined', room: msg.room, members: room.getMembers() }));
        break;
      }
      case 'message': {
        if (!username) return;
        const state = userSockets.get(username);
        if (!state?.currentRoom) return;
        const room = rooms.get(state.currentRoom);
        room?.broadcast({ type: 'message', from: username, text: msg.text, room: state.currentRoom }, username);
        break;
      }
      case 'dm': {
        if (!username) return;
        const target = userSockets.get(msg.to);
        if (!target) {
          ws.send(JSON.stringify({ type: 'error', message: `User ${msg.to} is not online` }));
          return;
        }
        target.ws.send(JSON.stringify({ type: 'dm', from: username, text: msg.text }));
        break;
      }
      case 'who': {
        const online = [...userSockets.keys()];
        ws.send(JSON.stringify({ type: 'online', users: online }));
        break;
      }
    }
  });

  ws.on('close', () => {
    if (!username) return;
    const state = userSockets.get(username);
    if (state?.currentRoom) rooms.get(state.currentRoom)?.leave(username);
    userSockets.delete(username);
  });
});

console.log('Chat server listening on ws://localhost:8888');

